impl core :: fmt :: Display for CaptureError { fn fmt (& self , f : & mut core :: fmt :: Formatter < '_ >) -> core :: fmt :: Result { match self { CaptureError :: UnknownPolicyRef { policy_ref } => { write ! (f , "policy_ref {policy_ref:?} is not in the registry — capture refuses rather \
                     than reconstructing a policy (G2/ADR-006)") } CaptureError :: RefMismatch { requested , resolved , } => { write ! (f , "registry corruption: requested {requested:?} but the stored policy hashes \
                     to {resolved:?}") } } } }

impl core :: fmt :: Display for ReplayError { fn fmt (& self , f : & mut core :: fmt :: Formatter < '_ >) -> core :: fmt :: Result { match self { ReplayError :: PolicyMismatch { recorded , captured } => write ! (f , "replay refused: the record was decided by {recorded:?} but the captured \
                 policy is {captured:?}") , ReplayError :: Select (e) => write ! (f , "replay selection refused: {e}") , ReplayError :: Diverged { recorded , replayed } => write ! (f , "replay diverged: recorded chose index {} (rule {:?}), replay chose index {} \
                 (rule {:?})" , recorded . chosen_index , recorded . matched_rule , replayed . chosen_index , replayed . matched_rule) , } } }
